import numpy as np

def gaussian(x, amplitude, center, width):
    return amplitude * np.exp(-((x - center) ** 2) / (2 * width ** 2))

def gaussian_jacobian(x, amplitude, center, width):
    d_amplitude = np.exp(-((x - center) ** 2) / (2 * width ** 2))
    d_center = amplitude * np.exp(-((x - center) ** 2) / (2 * width ** 2)) * ((x - center) / width ** 2)
    d_width = amplitude * np.exp(-((x - center) ** 2) / (2 * width ** 2)) * ((x - center) ** 2 / width ** 3)
    return np.column_stack((d_amplitude, d_center, d_width))

def gauss_newton_iteration(x_data, y_data, params):
    amplitude, center, width = params
    model = gaussian(x_data, amplitude, center, width)
    residuals = y_data - model
    jacobian = gaussian_jacobian(x_data, amplitude, center, width)
    update = np.linalg.lstsq(jacobian, residuals, rcond=None)[0]
    return params + update
